import{_ as h,o as n,c as a,ae as i}from"./chunks/framework.BeVX27ge.js";const s=JSON.parse('{"title":"Lịch sử","description":"","frontmatter":{},"headers":[],"relativePath":"history.md","filePath":"history.md"}'),c={name:"history.md"};function r(d,t,o,e,l,u){return n(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="lich-su" tabindex="-1">Lịch sử <a class="header-anchor" href="#lich-su" aria-label="Permalink to &quot;Lịch sử&quot;">​</a></h1><blockquote><p>Xem lại tất cả các bản ghi luyện tập, tìm kiếm hướng cải thiện thông qua phân tích và lọc.</p></blockquote><h2 id="tong-quan" tabindex="-1">Tổng quan <a class="header-anchor" href="#tong-quan" aria-label="Permalink to &quot;Tổng quan&quot;">​</a></h2><p>Trang Lịch sử cung cấp danh sách đầy đủ tất cả các bài thực hành của bạn, hỗ trợ lọc và sắp xếp đa chiều, giúp bạn dễ dàng tìm thấy các bản ghi luyện tập cụ thể để xem lại hoặc thực hành lại.</p><h2 id="cach-truy-cap" tabindex="-1">Cách Truy cập <a class="header-anchor" href="#cach-truy-cap" aria-label="Permalink to &quot;Cách Truy cập&quot;">​</a></h2><ul><li>Lựa chọn <strong>&quot;Tất cả&quot;</strong> trong phần lọc nhanh của Bảng điều khiển</li><li>Truy cập trực tiếp đường dẫn <code>/practice-history</code></li></ul><h2 id="cau-truc-trang" tabindex="-1">Cấu trúc Trang <a class="header-anchor" href="#cau-truc-trang" aria-label="Permalink to &quot;Cấu trúc Trang&quot;">​</a></h2><p>Trang Lịch sử bao gồm các khu vực sau:</p><ul><li><strong>Thanh Tiêu đề</strong>: Gồm Tiêu đề &quot;Lịch sử Luyện tập&quot;, Nút Bộ lọc, Nút Bắt đầu Trò chuyện</li><li><strong>Nhãn Lọc</strong>: Hiển thị các điều kiện lọc đang áp dụng</li><li><strong>Bảng Lịch sử</strong>: Hiển thị toàn bộ lịch sử luyện tập</li></ul><hr><h2 id="tinh-nang-loc" tabindex="-1">Tính năng Lọc <a class="header-anchor" href="#tinh-nang-loc" aria-label="Permalink to &quot;Tính năng Lọc&quot;">​</a></h2><p>Nhấp vào nút <strong>&quot;Bộ lọc&quot;</strong> để mở bảng điều khiển lọc. Bạn có thể áp dụng nhiều bộ lọc cùng một lúc.</p><table tabindex="0"><thead><tr><th>Tiêu chuẩn Lọc</th><th>Loại</th><th>Lựa chọn</th></tr></thead><tbody><tr><td>Độ Tuổi</td><td>Dải Số</td><td>Tuổi tối thiểu ~ Tuổi tối đa (18-65)</td></tr><tr><td>Giới tính</td><td>Lựa Chọn</td><td>Nam / Nữ</td></tr><tr><td>Tên</td><td>Văn Bản</td><td>Theo tên khách hàng</td></tr><tr><td>Thu nhập</td><td>Lựa Chọn</td><td>5M~10M / 10M~15M / 15M~20M / &gt; 20M</td></tr><tr><td>Tình trạng Hôn nhân</td><td>Lựa Chọn</td><td>Độc thân / Đã kết hôn</td></tr><tr><td>Loại Mối quan hệ</td><td>Lựa Chọn</td><td>Người thân / Người lạ</td></tr><tr><td>Giai đoạn Đạt được</td><td>Dải Số</td><td>Giai đoạn bán hàng tối thiểu ~ tối đa</td></tr></tbody></table><hr><h2 id="bang-lich-su" tabindex="-1">Bảng Lịch sử <a class="header-anchor" href="#bang-lich-su" aria-label="Permalink to &quot;Bảng Lịch sử&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Cột</th><th>Mô tả</th></tr></thead><tbody><tr><td>Ngày</td><td>Ngày và Thời gian thực hành</td></tr><tr><td>Tuổi</td><td>Tuổi của khách hàng</td></tr><tr><td>Giới tính</td><td>Giới tính của khách hàng</td></tr><tr><td>Tên</td><td>Tên khách hàng</td></tr><tr><td>Nghề nghiệp</td><td>Nghề nghiệp khách hàng</td></tr><tr><td>Thu nhập</td><td>Mức thu nhập khách hàng</td></tr><tr><td>Hôn nhân</td><td>Tình trạng hôn nhân (Độc thân / Đã kết hôn)</td></tr><tr><td>Con cái</td><td>Số lượng con</td></tr><tr><td>Mối quan hệ</td><td>Người thân / Người lạ</td></tr><tr><td>Giai đoạn Đạt được</td><td>Giai đoạn bán hàng cuối cùng</td></tr><tr><td>Thời lượng</td><td>Thời lượng trò chuyện</td></tr><tr><td>Thao tác</td><td>Các Tùy chọn Thao tác</td></tr></tbody></table><h3 id="nut-thao-tac" tabindex="-1">Nút Thao tác <a class="header-anchor" href="#nut-thao-tac" aria-label="Permalink to &quot;Nút Thao tác&quot;">​</a></h3><ul><li><strong>Xem Đánh giá</strong>: Chuyển đến báo cáo đánh giá để xem chi tiết kết quả.</li><li><strong>Thử lại</strong>: Tạo một bài thực hành hoàn toàn mới nhưng sử dụng cùng một khách hàng.</li><li><strong>Tiếp tục</strong>: Tiếp tục dở dang (chỉ dành cho các bài thực hành chưa kết thúc).</li></ul><hr><h2 id="loi-khuyen" tabindex="-1">Lời khuyên <a class="header-anchor" href="#loi-khuyen" aria-label="Permalink to &quot;Lời khuyên&quot;">​</a></h2><h3 id="tim-điem-yeu" tabindex="-1">Tìm Điểm yếu <a class="header-anchor" href="#tim-điem-yeu" aria-label="Permalink to &quot;Tìm Điểm yếu&quot;">​</a></h3><p>Lọc theo Giai đoạn Đạt được, tìm những bài luyện tập chỉ đạt Giai đoạn 1 hoặc 2. Xem Báo cáo Đánh giá để xác định điểm yếu và tập trung cải thiện trong tương lai.</p><h3 id="bai-tap-nhat-đinh" tabindex="-1">Bài tập Nhất định <a class="header-anchor" href="#bai-tap-nhat-đinh" aria-label="Permalink to &quot;Bài tập Nhất định&quot;">​</a></h3><p>Sử dụng bộ lọc (như Thu nhập, Hôn nhân) để tìm kiếm các loại khách hàng cụ thể. Sau đó sử dụng tính năng &quot;Thử lại&quot; để làm quen với các loại khách hàng gây khó khăn.</p><hr><h2 id="buoc-tiep-theo" tabindex="-1">Bước tiếp theo <a class="header-anchor" href="#buoc-tiep-theo" aria-label="Permalink to &quot;Bước tiếp theo&quot;">​</a></h2><ul><li>Quay trở lại <a href="./dashboard.html">Bảng điều khiển</a></li><li>Hiểu chuyên sâu <a href="./evaluation.html">Đánh giá &amp; Phản hồi</a></li><li>Bắt đầu <a href="./practice.html">Mô phỏng thực hành</a></li></ul>',27)])])}const p=h(c,[["render",r]]);export{s as __pageData,p as default};
